"""
mkt-christ — Nehemiah chapters 9–10
Run: python3 scripts/zc-christ-nehemiah-9-10.py

Ch 9 (38v): The great penitential prayer — a rehearsal of Israel's history from
  creation through the current Persian servitude; every act of divine faithfulness
  and every human failure points toward the one who fulfills the covenant that Israel
  repeatedly broke.
Ch 10 (39v): The covenant renewal — Nehemiah, priests, Levites, and the people
  sign a binding document committing to Torah observance; the specific commitments
  (Sabbath, intermarriage, tithes, firstfruits) all point forward to the new covenant
  that requires no such defensive legislation because the law is written on the heart.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(book, type_):
    p = ROOT / 'data' / 'commentary' / f'mkt-{type_}' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(book, type_, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{type_}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEH_CHRIST = {
  "9": {
    "1": "<p>The twenty-fourth day of the seventh month — four days after the Feast of Tabernacles ends — the Israelites assembled in fasting, in sackcloth, and with earth on their heads. The temporal proximity to the feast is significant: joy and repentance are not opposites in Israel's calendar but adjacent movements, the feast completed, the gravity of the covenant now felt. The assembly that meets for penitential prayer here foreshadows the community that gathers in response to the gospel — convicted, undone, beginning again from a posture of need rather than achievement.</p>",
    "2": "<p>'The descendants of Israel separated themselves from all foreigners and stood and confessed their sins and the iniquities of their fathers.' Confession requires the capacity to see clearly — to identify what one has done against a known standard. The confession of ancestral iniquities alongside personal sins reflects the solidarity of generations in covenant standing; the community bears not only its own failures but the accumulated weight of Israel's history of covenant breaking. This is precisely the burden that Christ bears on behalf of the whole community: 'he was pierced for our transgressions, he was crushed for our iniquities' (Isa 53:5) — the sins of generations lifted in a single act.</p>",
    "3": "<p>They stood for a quarter of the day while the Book of the Law was read, then confessed for another quarter. Six hours of Torah reading followed by six hours of confession — the order is important: hearing the word comes before the confession it generates. The community cannot confess what it has not yet heard; the Torah's specificity about what God requires is what makes the community's failure visible. This pattern of word-then-conviction is the structural pattern of the gospel: the proclamation of who God is and what he requires precedes the response of repentance and faith that the proclamation generates.</p>",
    "4": "<p>The Levites on the raised platform calling to YHWH with a loud voice — <em>zāʿaqû bᵉqôl gāḏôl ʾel-YHWH ʾĕlōhêhem</em>. The loud cry to God is the prayer posture of genuine distress, not liturgical propriety; it echoes the cry of Israel in Egypt that YHWH heard (Exod 2:23; 3:7-9) and the cry of the psalms (Ps 22:24; 130:1-2). Christ himself prays with loud crying and tears (Heb 5:7), identifying fully with those whose situation requires such urgent petition; his loud cry from the cross ('My God, my God, why have you forsaken me?' Ps 22:1) is the ultimate cry of need that no previous prayer had articulated.</p>",
    "5": "<p>'Stand up, bless YHWH your God from everlasting to everlasting.' The call to bless YHWH — the one who is from everlasting to everlasting — frames the entire prayer as a doxological act: the community is not merely reciting grievances but acknowledging the character of the God to whom they confess. 'Blessed be your glorious name, which is exalted above all blessing and praise' — the incomprehensibility of YHWH's glory (beyond all human categories of blessing and praise) is the foundation of the prayer. Christ's eternal existence 'from everlasting to everlasting' (John 1:1-2; 17:5) makes his intercession more than momentary — he prays from within the divine life itself.</p>",
    "6": "<p>'You are the LORD, you alone. You have made heaven, the heaven of heavens, with all their host, the earth and all that is on it, the seas and all that is in them; and you preserve all of them.' The prayer begins with creation because redemption presupposes creation — the God who saves Israel is the God who made all things. 'The host of heaven worships you': every created being exists in a posture of worship before the creator. John identifies Christ as the agent of creation: 'Through him all things were made; without him nothing was made that has been made' (John 1:3; Col 1:16-17); the God who preserves all things through the Son is the same God who redeems Israel through the covenant.</p>",
    "7": "<p>'You are the LORD God who chose Abram and brought him out of Ur of the Chaldeans and gave him the name Abraham.' The divine choice of Abraham — from among all the peoples of the ancient world, from the idol-worshipping culture of Mesopotamia — is the first act of covenant election in the prayer. Paul identifies Abraham's election as the model for the salvation of all who believe: 'Those who have faith are blessed along with Abraham, the man of faith' (Gal 3:9); Christ is the 'seed' of Abraham in whom the blessings of the Abrahamic covenant are concentrated and made available to all nations (Gal 3:16).</p>",
    "8": "<p>'You found his heart faithful before you, and made with him the covenant to give to his descendants the land of the Canaanites... You have kept your promise, for you are righteous.' Abraham's faithfulness and God's covenant faithfulness are presented as two sides of the same act — the covenant is made because Abraham's heart was found faithful, and God keeps it because he is righteous. Paul reverses neither: Abraham's faith is credited as righteousness (Gen 15:6; Rom 4:3), and God's covenant promise runs through the 'offspring' who is Christ (Gal 3:16). Every fulfilled covenant promise is a revelation of divine righteousness that reaches its climax in Christ, 'whom God put forward as a propitiation' (Rom 3:25-26).</p>",
    "9": "<p>'And you saw the affliction of our fathers in Egypt and heard their cry at the Red Sea.' YHWH's seeing and hearing — the divine attention turned toward human suffering — is the motivation of the Exodus. The God who sees affliction and hears crying is the revelation of divine character that stands behind all of redemptive history: 'God heard their groaning, and God remembered his covenant' (Exod 2:24). Christ's incarnation is the ultimate 'seeing and hearing' of human affliction — 'we have one who has been tempted in every way, just as we are' (Heb 4:15); the Son enters the affliction itself rather than merely observing it from outside.</p>",
    "10": "<p>'You performed signs and wonders against Pharaoh and all his servants and all the people of his land, for you knew that they acted arrogantly against our ancestors.' The signs and wonders against Egypt established YHWH's authority over the world's superpower and demonstrated that the covenant God was sovereign over all nations, not merely Israel's tribal deity. The NT reads the plagues and Exodus as a type of the final judgment and final redemption: 'Our ancestors were all under the cloud and all passed through the sea' (1 Cor 10:1); Christ's death and resurrection are the ultimate signs and wonders that defeat the ultimate Pharaoh — death and the powers that enslave through fear of death (Heb 2:14-15).</p>",
    "11": "<p>'You divided the sea before them, so that they went through the sea on dry ground, and you cast their pursuers into the depths, like a stone into mighty waters.' Paul identifies the Red Sea crossing as a baptism into Moses (1 Cor 10:1-2): 'they were all baptized into Moses in the cloud and in the sea.' Christian baptism is the antitype — the believer passes through the water and is united with Christ's death and resurrection (Rom 6:3-4). The sea that destroyed the enemy becomes the water that saves the people; the cross similarly is simultaneously judgment (on sin and the powers) and salvation (for those united with Christ).</p>",
    "12": "<p>'You led them by day with a pillar of cloud, and by night with a pillar of fire, to give them light on the way they should go.' The pillar of cloud and fire was the visible, mobile presence of YHWH accompanying Israel — a continuous, tangible, light-giving guide. Christ claims to be the fulfillment of this function: 'I am the light of the world. Whoever follows me will never walk in darkness but will have the light of life' (John 8:12). The pillar preceded Israel; Christ goes before his community (John 10:4; Heb 12:2) as the pioneer and perfecter of faith who has already traveled the path that leads to life.</p>",
    "13": "<p>'You came down on Mount Sinai and spoke with them from heaven and gave them right ordinances and true laws, good statutes and commandments.' YHWH's descent to Sinai — the coming down of the divine presence to meet the human community — is a type of the incarnation. The law was given through angels from the heavenly throne (Acts 7:53; Gal 3:19; Heb 2:2); Christ came himself, in person, without angelic intermediaries: 'Long ago God spoke to our ancestors in many and various ways by the prophets, but in these last days he has spoken to us by a Son' (Heb 1:1-2). The law given at Sinai was 'good and true'; the word given through the Son surpasses it.</p>",
    "14": "<p>'You made known to them your holy Sabbath and commanded them commandments, statutes, and a law through your servant Moses.' The Sabbath commandment is singled out from all the Sinai legislation — its distinctive character as the sign of the covenant between YHWH and Israel (Exod 31:13; Ezek 20:12) makes it the liturgical boundary marker of covenant relationship. Christ declares himself 'Lord of the Sabbath' (Mark 2:28) — not abolishing the Sabbath principle but claiming lordship over it and fulfilling its deepest meaning: the rest that remains for the people of God (Heb 4:9-11) is not a weekly ceremony but a permanent participation in Christ's completed work.</p>",
    "15": "<p>'You gave them bread from heaven for their hunger and brought water for them out of the rock for their thirst, and you told them to go in to possess the land that you had sworn to give them.' The double provision — bread and water in the wilderness — is the type that John records Jesus claiming: 'I am the bread of life... Whoever eats this bread will live forever' (John 6:35,51) and 'Whoever drinks the water I give them will never thirst' (John 4:14). Paul identifies the rock as Christ (1 Cor 10:4); the wilderness provision was a foretaste of the person who is himself both sustenance and rest for the weary pilgrim.</p>",
    "16": "<p>'But they and our ancestors acted presumptuously and stiffened their neck and did not obey your commandments.' The generational solidarity in sin — 'they and our ancestors' — places the confessing community within the ongoing history of human inability to keep the covenant. The stiff neck (<em>qiššû ʾeṯ-ʿorpām</em>) is the recurring metaphor for covenant stubbornness (Exod 33:5; Deut 9:6); it describes not occasional failure but a structural resistance to yielding to divine authority. Jer 31:33 announces the new covenant remedy: 'I will put my law within them, and I will write it on their hearts' — overcoming stiff-necked covenant failure from the inside rather than merely legislating it from the outside.</p>",
    "17": "<p>'They refused to obey and were not mindful of the wonders you performed among them, but they stiffened their neck and appointed a leader to return to their slavery in Egypt. But you are a forgiving God, gracious and merciful, slow to anger and abounding in steadfast love, and did not forsake them.' The announcement of God's character at the crisis point — 'you are a forgiving God' — is the revelation of divine nature that Paul expounds: God demonstrates his love in that while we were still sinners, Christ died for us (Rom 5:8). The refusal to remember God's acts, the regression to old bondage, the divine forgiveness that does not abandon — Christ is the enactment of this divine character, not merely its announcement.</p>",
    "18": "<p>'Even when they had made for themselves a golden calf and said, \"This is your God who brought you up out of Egypt,\" and had committed great blasphemies, you in your great mercies did not forsake them in the wilderness.' The golden calf — Israel's worst early apostasy, the substitution of a creature for the creator at the very moment the covenant was being formalized — was met not with destruction but with mercy. Paul uses the golden calf episode as the paradigmatic warning for the church (1 Cor 10:7-11), but the mercy that YHWH showed Israel is the same mercy that underlies the new covenant: Christ intercedes even for those who commit the covenant equivalent of idolatry — 'he always lives to make intercession for them' (Heb 7:25).</p>",
    "19": "<p>'In your great mercies you did not forsake them in the wilderness. The pillar of cloud to lead them in the way did not depart from them by day, nor the pillar of fire by night to give them light on the way they should go.' After the golden calf apostasy, the pillar of cloud and fire was not withdrawn — YHWH's guiding presence continued despite Israel's worst sin. The persistence of divine guidance after human failure is the pattern fulfilled in Christ's promise: 'I will never leave you or forsake you' (Heb 13:5); and 'surely I am with you always, to the very end of the age' (Matt 28:20). The unfailing presence of God in the wilderness shadows the unfailing presence of Christ with his community.</p>",
    "20": "<p>'You gave your good Spirit to instruct them. You did not withhold your manna from their mouths and gave them water for their thirst.' The threefold provision — Spirit, manna, water — is a type of the new covenant's provision. The gift of the 'good Spirit' (<em>rûḥᵃḵā haṭṭôḇāh</em>) for instruction in the wilderness anticipates the Spirit who 'will guide you into all the truth' (John 16:13); the manna anticipates the bread of life (John 6); the water anticipates the living water (John 7:37-39). Christ is the fulfillment of all three: the one who gives the Spirit (John 20:22), who is himself the bread (John 6:35), and from whom rivers of living water flow (John 7:38-39).</p>",
    "21": "<p>'Forty years you sustained them in the wilderness, so that they lacked nothing; their clothes did not wear out and their feet did not swell.' The 40-year wilderness provision — nothing worn out, nothing lacking — declares that YHWH's provision is sufficient for the entire duration of the journey, however long. This total provision finds its antitype in Paul's declaration: 'My God will supply every need of yours according to his riches in glory in Christ Jesus' (Phil 4:19) and 'we are more than conquerors through him who loved us' (Rom 8:37). Christ's provision for his community is not just for the good days but for the entire wilderness journey.</p>",
    "22": "<p>'You gave them kingdoms and peoples and allotted to them every corner. So they took possession of the land of Sihon king of Heshbon and the land of Og king of Bashan.' The conquest of the Transjordanian kingdoms (Num 21:21-35) was the first demonstration that YHWH could defeat fortified kingdoms — preparation for the land. Paul sees the conquest as a type of Christ's victory: 'He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him' (Col 2:15). Every conquered kingdom in the OT is a shadow of the definitive conquest in which Christ defeats every principality and power.</p>",
    "23": "<p>'You multiplied their children as the stars of heaven, and you brought them into the land that you had told their fathers to enter and possess.' The multiplication of Abraham's descendants to stellar numbers fulfilled the Abrahamic promise (Gen 15:5; 22:17). Paul identifies the true 'stars' as those who belong to Christ: 'If you belong to Christ, then you are Abraham's offspring, heirs according to promise' (Gal 3:29); 'those who are led by the Spirit of God are the sons of God... heirs of God and co-heirs with Christ' (Rom 8:14-17). The stellar multiplication is fulfilled not in ethnic Israel alone but in the countless redeemed from every nation (Rev 7:9).</p>",
    "24": "<p>'So the descendants went in and possessed the land, and you subdued before them the inhabitants of the land, the Canaanites, and gave them into their hand, with their kings and the peoples of the land, to do with them as they will.' The conquest narrative — enemies subdued, kings delivered, peoples given into Israel's hand — is the type of Christ's universal victory: 'All authority in heaven and on earth has been given to me' (Matt 28:18). The subjection of Canaan's kingdoms to Israel is a shadow of the subjection of all things to Christ: 'For he must reign until he has put all his enemies under his feet' (1 Cor 15:25).</p>",
    "25": "<p>'And they captured fortified cities and a rich land, and took possession of houses full of all good things, wells already dug, vineyards, olive orchards and fruit trees in abundance. So they ate and were satisfied and became fat and delighted themselves in your great goodness.' The land's abundance — all already prepared, nothing needing to be built from scratch — is a type of the inheritance Christ secures: 'I go to prepare a place for you... that where I am you may be also' (John 14:2-3). The community that enters the new covenant inheritance enters what has already been prepared — a grace-given abundance rather than self-generated prosperity.</p>",
    "26": "<p>'Nevertheless, they were disobedient and rebelled against you and cast your law behind their back and killed your prophets, who had warned them in order to turn them back to you, and they committed great blasphemies.' The killing of the prophets is the culmination of Israel's apostasy cycle — from law-breaking to prophet-killing. Jesus traces this line explicitly: 'O Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you' (Matt 23:37); 'Jerusalem, Jerusalem... Was there ever a prophet your fathers did not persecute?' (Acts 7:52). The rejection of the prophets reaches its terminus in the rejection of the Son himself: 'The stone the builders rejected has become the cornerstone' (Ps 118:22; Matt 21:42).</p>",
    "27": "<p>'Therefore you gave them into the hand of their enemies, who made them suffer. And in the time of their suffering they cried out to you and you heard them from heaven, and according to your great mercies you gave them deliverers who saved them from the hand of their enemies.' The Judges cycle — punishment, cry, deliverance — is the OT structure that points toward the final deliverer. Each judge was a partial and temporary savior; Israel cried out again after each deliverance. The final judge and deliverer is Christ, whose salvation is not temporary but permanent: 'he is able to save to the uttermost those who draw near to God through him, since he always lives to make intercession for them' (Heb 7:25). No more cries for deliverance from the same bondage — his salvation is once-for-all.</p>",
    "28": "<p>'But after they had rest they did evil again before you, and you abandoned them to the hand of their enemies, so that they had dominion over them. Yet when they turned and cried to you, you heard from heaven, and many times you delivered them according to your mercies.' The pattern of repeated apostasy and repeated deliverance reveals both the stubbornness of human nature and the inexhaustible mercy of YHWH. 'Many times you delivered them' — the plural is the key: each deliverance was partial and the need returned. The new covenant promises a different kind of mercy: 'I will remember their sins no more' (Heb 8:12) — not repeated deliverance from recurring bondage but a definitive, once-for-all liberation that does not have to be repeated.</p>",
    "29": "<p>'And you warned them in order to turn them back to your law. Yet they acted presumptuously and did not obey your commandments, but sinned against your rules, which if a person does them, he shall live by them, and they turned a stubborn shoulder and stiffened their neck and would not obey.' The phrase 'the person who does them shall live by them' (<em>ʾᵃšer yaʿᵃśeh ʾōṯām hāʾāḏām wāḥay bāhem</em>) — from Lev 18:5 — is the standard of life-through-obedience that Israel could not meet. Paul cites this exact phrase (Lev 18:5; Rom 10:5; Gal 3:12) to contrast law-righteousness with faith-righteousness: 'the law is not of faith, but the one who does them shall live by them' (Gal 3:12). The impossibility of living by the law drives the community toward the one who kept it perfectly and whose righteousness is credited to those who trust him (Phil 3:9).</p>",
    "30": "<p>'Many years you bore with them and warned them by your Spirit through your prophets. Yet they would not give ear. Therefore you gave them into the hand of the peoples of the lands.' The Spirit's work through the prophets — patient, sustained testimony across generations — is the precursor of the Spirit's definitive outpouring. 'Long ago God spoke to our ancestors in many and various ways by the prophets, but in these last days he has spoken to us by a Son' (Heb 1:1-2). The patience of the Spirit through all the prophets was preparation for the full revelation; the Spirit who spoke through Elijah and Jeremiah now dwells in the community of the Son (John 14:16-17).</p>",
    "31": "<p>'Nevertheless, in your great mercies you did not make an end of them or forsake them, for you are a gracious and merciful God.' The prayer reaches its theological center: the inexhaustibility of divine mercy. 'You did not make an end of them' — despite every provocation, despite every cycle of rebellion, despite the exile itself, YHWH did not bring the covenant line to extinction. This preserving mercy is inseparable from the promise of a remnant (Isa 10:20-22; Rom 9:27) through whom the covenant purposes would be fulfilled; Christ is the one in whom the remnant is concentrated, the 'stump of Jesse' from which the new shoot grows (Isa 11:1; Rom 15:12).</p>",
    "32": "<p>'Now therefore, our God, the great, the mighty, and the awesome God, who keeps covenant and steadfast love, do not let all the hardship seem little to you that has come upon us... from the time of the kings of Assyria until today.' The prayer turns from history to petition: given all this history of covenant faithfulness on YHWH's side, the community asks that their current suffering not be dismissed. The appeal is to God's covenant character — 'the great, the mighty, and the awesome God, who keeps covenant and steadfast love.' Christ mediates this petition: 'we have a great high priest who has passed through the heavens' (Heb 4:14) who brings the community's suffering before the Father and ensures it is neither forgotten nor dismissed.</p>",
    "33": "<p>'Yet you have been righteous in all that has come upon us, for you have dealt faithfully and we have acted wickedly.' The confession of divine righteousness in the face of suffering — 'you have been righteous in all that has come upon us' — is one of the most striking declarations in the prayer. The community does not blame God for the exile but acknowledges it as just; YHWH has been consistently faithful while they have been consistently unfaithful. This is the same theological logic Paul employs: 'God was justified in his words and prevailed when he was judged' (Rom 3:4, citing Ps 51:4); and it is the logic of the cross — God is 'just and the justifier of the one who has faith in Jesus' (Rom 3:26).</p>",
    "34": "<p>'Our kings, our princes, our priests, and our ancestors have not kept your law or paid attention to your commandments and your warnings that you gave them.' The comprehensive confession — every level of leadership (kings, princes, priests) and every generation (ancestors) — establishes that the failure is systemic and total, not reducible to a few bad actors. This total failure is what makes substitutionary redemption necessary: no representative from within the existing order can solve the problem because every member of that order is compromised. The high priest who can 'sympathize with our weaknesses' must be 'one who in every respect has been tempted as we are, yet without sin' (Heb 4:15) — wholly within the human situation but without sharing its failure.</p>",
    "35": "<p>'Even in their own kingdom, and amid your great goodness that you gave them, and in the large and rich land that you set before them, they did not serve you or turn from their evil works.' The indictment is deepened: not poverty or persecution drove them to sin, but prosperity. Sin in the midst of abundance is harder to excuse than sin from deprivation; the failure was not circumstantial but structural — rooted in the human heart that turns away from God precisely when external need no longer compels turning toward him. Deut 8:10-20 had warned exactly this; the exile confirmed it. Christ comes not to improve the circumstances but to change the heart: 'I will give you a new heart and put a new spirit in you' (Ezek 36:26).</p>",
    "36": "<p>'Behold, we are servants this day; in the land that you gave to our fathers to eat its fruit and its good things, behold, we are servants in it.' The humiliation of being servants in their own land — possessing the geography of the covenant inheritance while being politically subordinate to a foreign empire — is the crisis the prayer identifies. The community is in the land but not free; they have the promise but not the fulfillment. Christ's announcement echoes: 'the truth will set you free... everyone who sins is a slave to sin... So if the Son sets you free, you will be free indeed' (John 8:32-36). True freedom is not geographic or political but covenantal — a freedom that neither Rome nor Persia could grant or take away.</p>",
    "37": "<p>'Its rich yield goes to the kings whom you have set over us because of our sins. They rule over our bodies and over our livestock as they will, and we are in great distress.' The condition of Persian servitude — laboring for others' kingdoms on the land YHWH gave to Israel — is both political oppression and theological statement: their sin has given the yield of their inheritance to others. Christ's redemption reverses this: 'you were bought with a price' (1 Cor 6:20) — the one who was himself given over to the powers of this age ('the ruler of this world is coming and has no claim on me,' John 14:30) redeems those who had given themselves over to the same powers through sin.</p>",
    "38": "<p>'Because of all this we are making a firm covenant in writing; on the sealed document are the names of our princes, our Levites, and our priests.' The written, sealed covenant — the community's formal response to the prayer and confession of ch9 — is the human side of a covenant that only God can keep. The very need to write and seal a covenant document indicates the community's awareness that verbal commitment alone is insufficient; they want a binding, externally visible, formally attested commitment. But the new covenant God promises does not need to be written on stone or parchment: 'I will put my law within them, and I will write it on their hearts' (Jer 31:33; Heb 8:10). The sealed document of Nehemiah 10 is the last gasp of the old covenant's self-enforcing mechanism; the new covenant works by a different principle.</p>"
  },
  "10": {
    "1": "<p>Nehemiah the governor (<em>hattiršāṯāʾ</em>) heads the list of covenant-signers. That the civil governor signs first — before the priests — reflects the integrated nature of the restoration community's authority structure. Nehemiah's signing represents the full weight of civic governance committed to covenant obedience. In the new covenant, Christ himself is the ultimate civil-priestly authority who mediates the covenant — 'the mediator of a new covenant' (Heb 9:15) who signs it not with ink but with his own blood (Luke 22:20).</p>",
    "2": "<p>Seraiah the priest is listed first among the priestly signers. The priestly community's formal covenant commitment demonstrates that the temple apparatus is fully aligned with the covenant's demands. The priestly role in the new covenant is fulfilled in Christ, the great high priest who 'offered himself once to bear the sins of many' (Heb 9:28) and whose single act replaces the ongoing priestly covenant-maintenance of the old order.</p>",
    "3": "<p>Amariah, Malchijah, Pashur — three priestly families committing to covenant faithfulness. Their individual signatures matter: each family's participation signifies that the priestly institution as a whole is bound to the covenant. In the new covenant, the entire community of believers is a 'royal priesthood' (1 Pet 2:9) — not a specialized class but all those united to the great high priest.</p>",
    "4": "<p>Hattush, Shebaniah, Malluch — more priestly signers. The list's detail serves the same function as the Ezra 2 census: names matter covenantally. To be named in the covenant document is to be identified as belonging to the covenant people. The NT parallel is the 'book of life' (Phil 4:3; Rev 21:27) — the eschatological covenant register in which the names of those who belong to Christ are written.</p>",
    "5": "<p>Harim, Meremoth, Obadiah — the priestly list continues. Meremoth son of Uriah had received the temple vessels from Ezra's caravan (Ezra 8:33) and repaired sections of the wall (Neh 3:4, 21); his multiple roles demonstrate how the same individuals served across both the cultic and civic dimensions of the restoration. Christ encompasses both: 'in him all the fullness of God was pleased to dwell' (Col 1:19) — the one in whom every restoration role is concentrated and fulfilled.</p>",
    "6": "<p>Daniel, Ginnethon, Baruch — continuing the priestly registry. Baruch was a common name in the restoration period (cf. Baruch son of Neriah, Jeremiah's secretary, Jer 32:12). Each named individual represents a household, an extended family, a lineage that is now formally committed to the covenant's demands. The formal commitment of named individuals to covenant obedience is the old covenant's way of achieving what the new covenant achieves through the work of the Spirit in the heart.</p>",
    "7": "<p>Meshullam, Abijah, Mijamin — Abijah's priestly division is the one in which Zechariah the father of John the Baptist served (Luke 1:5), making this family's covenant signature in Nehemiah 10 a link in the chain that leads directly to the forerunner of the Messiah. The small, named family of Abijah signing a covenant document in Jerusalem carries the thread that will produce the voice 'crying in the wilderness' (Isa 40:3; Mark 1:3).</p>",
    "8": "<p>Maaziah, Bilgai, Shemaiah — completing the priestly signers. The list of 21 priestly names is followed by the Levitical and lay leaders, showing that the covenant commitment is comprehensive — all three estates of the covenant community (priestly, Levitical, lay leadership) formally join the document. This comprehensiveness anticipates the new covenant's reach: 'they shall all know me, from the least of them to the greatest' (Jer 31:34; Heb 8:11).</p>",
    "9": "<p>The Levitical signers begin with Jeshua son of Azaniah, Binnui of the sons of Henadad, and Kadmiel — three leading Levitical families of the restoration period. Kadmiel appears in the Ezra 2 return list, the wall-building narratives, and the worship leadership of Neh 9; his signature here connects the entire Ezra-Nehemiah narrative to this formal covenant commitment. The Levites were the community's teachers and liturgical leaders — their formal covenant commitment was essential for the ongoing instruction and worship that sustained covenant life.</p>",
    "10": "<p>Sherebiah, Hodijah, Kelita, Pelaiah, Hanan — Levitical leaders. Sherebiah was one of the key Levites who helped Ezra read and explain the Torah (Neh 8:7) and led the confession of ch9; his signature here connects the teaching office to the covenantal commitment. The Levitical teachers who explain the law also bind themselves to its demands — their personal covenant faithfulness is inseparable from their instructional role.</p>",
    "11": "<p>Micha, Rehob, Hashabiah — more Levitical signers. Hashabiah appears in Neh 11:15 as an overseer of the Levites in Jerusalem and in 12:24 as a Levitical leader of thanksgiving; the covenant document names those who will implement the commitments of vv30-39 in daily institutional life. The new covenant's teachers are similarly those who are 'transformed by the renewing of your mind' (Rom 12:2) before they teach — formation precedes instruction.</p>",
    "12": "<p>Zaccur, Sherebiah, Shebaniah — the Levitical list continues. Multiple individuals named Sherebiah appear in the restoration records, showing how names recur across priestly and Levitical families; each instance is a distinct person and household adding their commitment to the covenant document.</p>",
    "13": "<p>Hodijah, Bani, Beninu — completing the named Levitical signers. The Levitical list of 17 names represents the teaching and musical infrastructure of the post-exilic community; their formal covenant commitment ensures that the community's liturgical and educational apparatus is not merely performing rituals but personally bound to the covenant they administer.</p>",
    "14": "<p>The lay leaders begin: Parosh, Pahath-moab, Elam, Zattu, Bani — all families from the first-return census of Ezra 2 and Neh 7. The lay leaders' covenant commitment extends the document beyond the religious professionals into the economic and social life of the community. The new covenant similarly reaches beyond cultic observance into the whole of life: 'whether you eat or drink, or whatever you do, do all to the glory of God' (1 Cor 10:31).</p>",
    "15": "<p>Bunni, Azgad, Bebai — more lay families from the census lists. The appearance of the same family names in the return lists, the wall-building accounts, and now the covenant document traces the continuity of specific families across the entire Ezra-Nehemiah narrative — the same households who returned under Zerubbabel, rebuilt under Nehemiah, and now commit themselves to the covenant form the institutional backbone of the restoration community.</p>",
    "16": "<p>Adonijah, Bigvai, Adin — three more prominent lay families. Their participation in the covenant document signals that the wealthy and influential members of the community are formally bound to the same Torah obligations as the priests and Levites — no social class is exempt from the covenant's demands. Christ similarly makes no social distinction in his call: 'Come to me, all who labor and are heavy laden' (Matt 11:28).</p>",
    "17": "<p>Ater, Hezekiah, Azzur — continuing the lay leaders. The diversity of family backgrounds represented in the covenant document (farmers, traders, administrators, returning exiles from different Babylonian communities) reflects the social breadth of the covenant commitment. The same breadth characterizes the new covenant community: 'There is neither Jew nor Greek, slave nor free, male nor female, for you are all one in Christ Jesus' (Gal 3:28).</p>",
    "18": "<p>Hodijah, Hashum, Bezai — three more families. Hashum's descendants had been among those who had married foreign wives and were required to divorce them under Ezra's reform (Ezra 10:33); now they are among the covenant signers committing to exactly the prohibition their family had previously violated. The presence of repentant families among the covenant signers shows that the document is not merely a confirmation of the already faithful but a commitment by those who know their own history of failure.</p>",
    "19": "<p>Hariph, Anathoth, Nebai — the name Anathoth here refers to a family rather than the town. Anathoth as a family name carries the association of the town of Jeremiah — the prophet whose entire ministry was devoted to calling Israel back to covenant faithfulness; to bear the name Anathoth while signing the covenant document is to embody the call Jeremiah spent his life making.</p>",
    "20": "<p>Magpiash, Meshullam, Hezir — three more lay leaders. Meshullam is a common name in the restoration community (at least 17 individuals bear this name across Ezra-Nehemiah); its recurrence shows the density of these lay leadership families and their consistent presence across every major institutional act of the restoration — return, wall-building, covenant-signing.</p>",
    "21": "<p>Meshezabel, Zadok, Jaddua — Jaddua is notable as also the name of the last high priest mentioned in the OT (Neh 12:11); whether this is the same individual or a different person bearing the same name, the name Jaddua appears at both the beginning and end of the post-exilic priestly succession, framing the entire restoration period.</p>",
    "22": "<p>Pelatiah, Hanan, Anaiah — the lay leader list continues. Hanan appears in multiple roles in Nehemiah's administration (one of the storeroom treasurers in Neh 13:13); the individual who manages the material resources of the community is also personally signed to the covenant — administrative faithfulness and covenantal commitment are integrated, not separated.</p>",
    "23": "<p>Hoshea, Hananiah, Hashub — Hananiah is the name of multiple people in Nehemiah's Jerusalem, including the wall-builder (Neh 3:8) and the governor of the citadel (Neh 7:2). The multiplication of the same name across the restoration community shows that these are covenant names — names that mean 'YHWH is gracious' and 'YHWH has been gracious' — chosen by families who wished to identify themselves with the grace of the God whose covenant they were now formally entering.</p>",
    "24": "<p>Hallohesh, Pilha, Shobek — Hallohesh ('the whisperer/enchanter') is an unusual name for a covenant signer; its presence reminds that the covenant document includes those with unexpected backgrounds. The new covenant similarly reaches those who come from surprising places: 'God chose what is low and despised in the world, even things that are not, to bring to nothing things that are, so that no human being might boast in the presence of God' (1 Cor 1:28-29).</p>",
    "25": "<p>Rehum, Hashabnah, Maaseiah — three more signers completing the lay list. The name Maaseiah ('work of YHWH') appears more than 20 times in the OT; its frequency in the restoration community suggests it was favored as a statement of identity — the people who bore this name identified themselves as 'YHWH's work,' which is precisely what they were as a restored community reconstituted by divine grace.</p>",
    "26": "<p>Ahijah, Hanan, Anan — three more lay leaders. Ahijah means 'brother of YHWH' — a name that carries the covenant relationship language of kinship; to be YHWH's brother is to be in the closest possible covenant bond. The new covenant makes this metaphorical kinship concrete: 'he is not ashamed to call them brothers' (Heb 2:11) — Christ himself takes the title that Ahijah's family bore as their covenant identity.</p>",
    "27": "<p>Malluch, Harim, Baanah — the final three lay signers. With 84 named individuals across vv1-27 (Nehemiah + 83 others), the covenant document is comprehensively attested. The 84 signers represent the full institutional structure of the restoration community: governor, priests, Levites, and lay leaders. The comprehensiveness of the signing mirrors the comprehensiveness of the new covenant: 'from the least of them to the greatest, they shall all know me' (Jer 31:34).</p>",
    "28": "<p>'The rest of the people... everyone who had knowledge and understanding, entered into a curse and an oath to walk in God's Law that was given by Moses the servant of God.' The community joining the covenant beyond the named signers shows that the document is not merely elite commitment but encompasses the whole people — servants, gatekeepers, temple singers, those 'separated from the peoples of the lands' to join Israel. This inclusive joining anticipates the new covenant's reach to all who respond: 'whoever believes in him should not perish but have eternal life' (John 3:16) — the covenant entry is open to any who will come.</p>",
    "29": "<p>'They joined with their brothers, their nobles, and entered into a curse and an oath to walk in God's Law that was given by Moses the servant of God, and to observe and do all the commandments of the LORD our Lord and his rules and his statutes.' The self-imposed curse for covenant violation is the old covenant's enforcement mechanism — the community calls divine punishment on itself if it breaks the terms. Christ absorbed this covenant curse: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The curse that the Nehemiah community placed on themselves for future potential violations, Christ bore as a present reality for past actual violations.</p>",
    "30": "<p>'We will not give our daughters to the peoples of the land or take their daughters for our sons.' The anti-intermarriage covenant commitment addresses the cultural assimilation that had led to every previous generation's apostasy. The theological principle behind it — the covenant community maintains its distinct identity and orientation — is preserved in the new covenant not through ethnic separation but through the transformation of the heart: 'Do not be unequally yoked with unbelievers' (2 Cor 6:14) is the new covenant application of the same principle, extended from ethnic identity to shared faith in Christ.</p>",
    "31": "<p>'And if the peoples of the land bring in goods or any grain on the Sabbath day to sell, we will not buy from them on the Sabbath or on a holy day. And we will forego the crops of the seventh year and the exaction of every debt.' The sabbatical-year and debt-release commitments point toward the Jubilee — YHWH's built-in economic reset for a society prone to permanent stratification. Jesus' inaugural sermon announces 'the year of the Lord's favor' (Luke 4:19, citing Isa 61:1-2) — the ultimate Jubilee in which all debts are forgiven, all captives released, all the poor given good news. The commitment of Nehemiah 10:31 is the old covenant's approximation; Christ's announcement is the new covenant's fulfillment.</p>",
    "32": "<p>'We also take on ourselves the obligation to give yearly a third part of a shekel for the service of the house of our God.' The temple tax — Moses had prescribed a half-shekel ransom (Exod 30:13), here reduced to a third-shekel by community agreement — funded the community's shared worship infrastructure. Matthew records that Christ paid the temple tax 'so that we do not give offense to them' (Matt 17:27) — not because he was obligated but as a voluntary act of solidarity. Christ pays the ultimate 'ransom for many' (Matt 20:28), the price that no coin could cover.</p>",
    "33": "<p>'The showbread, the regular grain offering, the regular burnt offering, the Sabbaths, the new moons, the appointed feasts, the holy things, and the sin offerings to make atonement for Israel' — the full liturgical calendar funded by the temple tax. Every item on this list points toward Christ: the showbread anticipates the bread of his presence (John 6:51); the burnt offering prefigures his total self-offering (Heb 10:5-10); the sin offering is fulfilled in 'God made him who had no sin to be sin for us' (2 Cor 5:21); the appointed feasts find their fulfillment in him as Passover, Firstfruits, and Tabernacles.</p>",
    "34": "<p>'We, the priests, the Levites, and the people, have likewise cast lots for the wood offering, to bring it into the house of our God... to burn on the altar of the LORD our God.' The wood offering supplied fuel for the altar fire — the continuous sacrifice required continuously burning wood. The fire was first lit by YHWH himself (Lev 9:24; 2 Chr 7:1), a divine fire that the community was commanded to keep burning. Christ is the one who 'baptizes with the Holy Spirit and fire' (Matt 3:11); the divine fire that fell on Pentecost (Acts 2:3) is the new covenant's fulfillment of the continuous fire — not a temple altar but the community of believers as the temple in which divine fire burns.</p>",
    "35": "<p>'We obligate ourselves to bring the firstfruits of our ground and the firstfruits of all fruit of every tree, year by year, to the house of the LORD.' Firstfruits acknowledged that the entire harvest belonged to YHWH and that the community's abundance was gift, not achievement. Paul identifies Christ as 'the firstfruits of those who have fallen asleep' (1 Cor 15:20, 23) — the first of the resurrection harvest that will include all who belong to him. The commitment to bring firstfruits to YHWH's house anticipates the community's recognition that Christ's resurrection is the firstfruits of the eschatological harvest of the dead.</p>",
    "36": "<p>'As it is written in the Law, we will bring the firstborn of our sons and of our cattle, as it is written in the Law, and the firstborn of our herds and of our flocks to the house of our God.' The firstborn belongs to YHWH — redeemed from death by sacrifice. Christ is 'the firstborn over all creation' (Col 1:15) and 'the firstborn from among the dead' (Col 1:18; Rev 1:5) — not merely a firstborn who requires redemption but the firstborn who is himself the means of redemption. He is the firstborn whom death could not hold, whose resurrection makes possible the redemption of all whom death holds.</p>",
    "37": "<p>'We will bring the first of our dough, our contributions, the fruit of every tree, the wine and the oil, to the priests, to the chambers of the house of our God; and we will bring the tithes from our ground to the Levites, for the Levites collect the tithes in all our towns where we labor.' The comprehensive system of tithes and offerings funded the covenant community's worship and instruction. Paul uses this system as the basis for supporting new covenant ministers (1 Cor 9:13-14) and as a metaphor for generous giving (2 Cor 9:6-15). Christ, as the great high priest, receives the ultimate 'tithe' — not a tenth of income but the whole life offered in living sacrifice (Rom 12:1).</p>",
    "38": "<p>'And the priest, the son of Aaron, shall be with the Levites when the Levites receive the tithes. And the Levites shall bring up the tithe of the tithes to the house of our God, to the chambers of the storehouse.' The tithe of tithes — the Levites' tithe of what they receive — creates a chain of giving from the whole people through the Levites to the priests: 'Bring the full tithe into the storehouse, that there may be food in my house' (Mal 3:10). The 'storehouse' of the new covenant temple is the community itself (1 Cor 3:16; Eph 2:21-22), built and sustained by Christ as the great high priest whose provision never runs out.</p>",
    "39": "<p>'For the people of Israel and the sons of Levi shall bring the contribution of grain, wine, and oil to the chambers where the vessels of the sanctuary are, where the priests who minister, and the gatekeepers and the singers are. We will not neglect the house of our God.' The closing pledge — 'we will not neglect the house of our God' — is the positive summation of every covenant commitment in the chapter. In the new covenant, 'the house of God' is not a temple building but the assembled community (1 Tim 3:15; Heb 10:21-25): 'not neglecting to meet together, as is the habit of some, but encouraging one another, and all the more as you see the Day drawing near' (Heb 10:25). The pledge to not neglect the house of God reaches its final form in the mutual commitment of believers to the body of Christ.</p>"
  }
}

def main():
    existing = load_comm('nehemiah', 'christ')
    merge_comm(existing, NEH_CHRIST)
    save_comm('nehemiah', 'christ', existing)
    added = sum(len(v) for v in NEH_CHRIST.values())
    print(f'nehemiah mkt-christ ch 9-10: wrote {added} verses')
    import json as _json, pathlib as _pathlib
    il = _json.loads(_pathlib.Path('data/interlinear/nehemiah.json').read_text())
    out = _json.loads(_pathlib.Path('data/commentary/mkt-christ/nehemiah.json').read_text())
    for ch in ['9', '10']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(out.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'  ch{ch} STILL MISSING: {sorted(missing, key=int)}')
        else:
            print(f'  ch{ch}: complete ({len(out_vv)} verses)')

if __name__ == '__main__':
    main()
